    if (!chamadosAgrupados[id]) {
        chamadosAgrupados[id] = {
            titulo: titulo,
            url: url,
            usuarios: []
        };
    }

    // Adiciona os dados do usuário à lista de usuários para este chamado
    chamadosAgrupados[id].usuarios.push({
        nomeCompleto: nomeCompleto,
        usuarioAd: usuarioAd,
        email: email,
        senhaPadrao: senhaPadrao
    });
}

// Obtém a saudação aleatória
const saudacao = obterSaudacao();

// Obtém a data atual
const dataAtual = obterDataAtual();

// Agora cria a mensagem unificada
for (const id in chamadosAgrupados) {
    const chamado = chamadosAgrupados[id];

    // Adiciona a saudação e a introdução
    mensagemUnificada += `${saudacao}\n\nAcessos criados!\n\n`;

    // Adiciona a informação de ID, TÍTULO e Data de Criação no início
    mensagemUnificada += `ID: ${id} - TITULO: ${chamado.titulo}\n`;
    mensagemUnificada += `Data de criação: ${dataAtual}\n\n`;

    // Adiciona as informações de cada usuário relacionado a este chamado
    for (const usuario of chamado.usuarios) {
        mensagemUnificada += `*${usuario.nomeCompleto}*\n`;
        mensagemUnificada += `- USUARIO AD: ${usuario.usuarioAd}\n`;
        mensagemUnificada += `- SENHA: ${usuario.senhaPadrao}\n`;
        mensagemUnificada += `- EMAIL: ${usuario.email}\n\n`;
    }

    // Adiciona o link para conferir o chamado
    mensagemUnificada += `Link do Chamado: ${chamado.url}\n\n`;
}

// Retorna a mensagem final no formato JSON contendo apenas uma string
return [
    {
        json: {
            textMessage: JSON.stringify(mensagemUnificada.trim())
        }
    }
];

// Entradas
const usuariosData = $('Merge1').all(); // Lista de dados de usuários recebidos
const usuariosExistentes = $('coletaDados')
    .all()
    .map(item => item.json.USUARIO)
    .filter(usuario => usuario); // Lista de usuários existentes

// Lista de palavras a serem ignoradas (preposições comuns)
const palavrasIgnoradas = ["de", "da", "do", "das", "dos"];

// Função para remover acentos
const removerAcentos = (str) =>
    str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();

// Função para gerar nomes de usuário
function gerarNomeUsuario(nomeCompleto, newCPF, usuariosExistentes) {
    const nomeSemAcentos = removerAcentos(nomeCompleto);
    const partesNome = nomeSemAcentos.split(" ").filter(p => p.length > 0 && !palavrasIgnoradas.includes(p));

    const primeiroNome = partesNome[0];
    let sobrenome = partesNome[partesNome.length - 1];
    let nomeUsuario = `${primeiroNome}.${sobrenome}`;
    let tentativa = 1;

    // Tenta variações do nome até encontrar um disponível
    while (usuariosExistentes.includes(nomeUsuario)) {
        if (tentativa === 1 && partesNome.length > 2) {
            sobrenome = partesNome[1]; // Segundo nome como sobrenome
        } else if (tentativa === 2 && partesNome.length > 3) {
            sobrenome = `${partesNome[1]}${partesNome[2]}`; // Combina segundo nome com próximo sobrenome
        } else {
            sobrenome = `${partesNome.slice(1).join("")}${tentativa}`; // Junta todos os sobrenomes com número
        }
        nomeUsuario = `${primeiroNome}.${sobrenome}`;
        tentativa++;
    }

    return { usuario: nomeUsuario, newCPF };
}

// Gerar os nomes de usuário para cada entrada recebida
const resultados = usuariosData.map(item => {
    const nomeCompleto = item.json.newNOME;
    const newCPF = item.json.newCPF;
    return gerarNomeUsuario(nomeCompleto, newCPF, usuariosExistentes);
});

// Retornar os resultados
return resultados;
